function Toast({ msg }) {
  if (!msg) return null;
  return (
    <div className="no-print fixed bottom-6 left-1/2 z-[70] -translate-x-1/2 rounded-full bg-stone-900 px-5 py-2.5 text-sm font-medium text-white shadow-lg">
      {msg}
    </div>
  );
}

